/**
 * @summary Get messages in a room
 */
export const getGetRoomMessagesUrl = (
  roomId: number,
  params?: GetRoomMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/rooms/${roomId}/messages?${stringifiedParams}`
    : `/api/rooms/${roomId}/messages`;
};

export const getRoomMessages = async (
  roomId: number,
  params?: GetRoomMessagesParams,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetRoomMessagesUrl(roomId, params), {
    ...options,
    method: "GET",
  });
};

export const getGetRoomMessagesQueryKey = (
  roomId: number,
  params?: GetRoomMessagesParams,
) => {
  return [
    `/api/rooms/${roomId}/messages`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetRoomMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof getRoomMessages>>,
  TError = ErrorType<ErrorResponse>,
>(
  roomId: number,
  params?: GetRoomMessagesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getRoomMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetRoomMessagesQueryKey(roomId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getRoomMessages>>> = ({
    signal,
  }) => getRoomMessages(roomId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!roomId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getRoomMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

